mapper.select:
/* authInqyDao1010 : 권한 목록 조회 */ SELECT AUTH_CD , AUTH_NM , USE_YN , DISP_ORDER , REMARK FROM AUTH WHERE 1=1
AND REGEXP_REPLACE(LOWER(AUTH_NM),'[^0-9가-힣A-Za-z]*','') LIKE '%'||REGEXP_REPLACE(LOWER(#{srchNm, jdbcType=VARCHAR}),'[^0-9가-힣A-Za-z]*','')||'%'
ORDER BY AUTH_CD

/* authInqyDao4010 : 사용자 권한 목록 조회 */ SELECT DATA.* FROM ( SELECT EA.AUTH_CD , A.AUTH_NM , EA.EMP_IDX , E.EMP_NM , D.ORG_NM , EA.DISP_ORDER FROM EMP_AUTH EA LEFT OUTER JOIN EMP_INFO E ON E.EMP_IDX = EA.EMP_IDX LEFT OUTER JOIN AUTH A ON A.AUTH_CD = EA.AUTH_CD AND A.USE_YN = 'Y' LEFT OUTER JOIN ORG D ON D.ORG_CD = E.ORG_CD WHERE 1=1
AND A.AUTH_CD = #{authCd, jdbcType=VARCHAR}
) DATA ORDER BY DATA.EMP_NM, DATA.EMP_IDX

mapper.insert:
/* authProcDao1010 : 권한 등록 처리 */
INSERT INTO AUTH
(
			AUTH_CD
		,	AUTH_NM
		,	USE_YN
		,	DISP_ORDER
		,	REMARK
)
VALUES
(
		(SELECT 'AUTH_' || LPAD(NVL(MAX(SUBSTR(AUTH_CD,LENGTH(AUTH_CD)-3,LENGTH(AUTH_CD))),0) + 1,4,0) AS AUTH_CD FROM AUTH)
	,	#{authNm, jdbcType=VARCHAR}
	,	#{useYn, jdbcType=VARCHAR}
	,	(
			SELECT 
				NVL(MAX(DISP_ORDER),0) + 1 
			FROM AUTH
		)
	,	#{remark, jdbcType=VARCHAR}
)

mapper.update:
/* authProcDao1020 : 권한 수정 처리 */
UPDATE AUTH
	SET		AUTH_NM = #{authNm, jdbcType=VARCHAR}
		,	USE_YN = #{useYn, jdbcType=VARCHAR}
		,	REMARK = #{remark, jdbcType=VARCHAR}
WHERE AUTH_CD = #{authCd, jdbcType=VARCHAR}

mapper.delete:
/* authProcDao1030 : 권한 삭제 처리 */
DELETE FROM AUTH
	WHERE AUTH_CD = #{authCd, jdbcType=VARCHAR}

/* authProcDao1040 : 메뉴 권한 삭제 처리 */
DELETE FROM MENU_AUTH
	WHERE AUTH_CD = #{authCd, jdbcType=VARCHAR}

